import json
import pymysql

# Database connection parameters
rds_host = "your_rds_host"
username = "your_username"
password = "your_password"
db_name = "your_database"

# Establish a connection to the RDS MySQL database
connection = pymysql.connect(host=rds_host, user=username, passwd=password, db=db_name)

def lambda_handler(event, context):
    search_params = event.get('queryStringParameters', {})
    
    # Start building the SQL query
    sql_query = "SELECT * FROM products WHERE 1=1"
    query_params = []
    
    # Dynamically add conditions based on search parameters
    if 'name' in search_params:
        sql_query += " AND name LIKE %s"
        query_params.append(f"%{search_params['name']}%")
    if 'category' in search_params:
        sql_query += " AND category = %s"
        query_params.append(search_params['category'])
    if 'price_min' in search_params:
        sql_query += " AND price >= %s"
        query_params.append(search_params['price_min'])
    if 'price_max' in search_params:
        sql_query += " AND price <= %s"
        query_params.append(search_params['price_max'])
    
    try:
        with connection.cursor() as cursor:
            cursor.execute(sql_query, query_params)
            results = cursor.fetchall()
        
        # Format the results as a list of dictionaries
        products = []
        for row in results:
            products.append({
                'id': row[0],
                'name': row[1],
                'category': row[2],
                'price': row[3],
                # Add other fields as necessary
            })
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }